111 static CallInst *InsertTrap(BuilderTy &IRB, bool DebugTrapBB,
112                             std::optional<int8_t> GuardKind) {
113   if (!DebugTrapBB)
114     return IRB.CreateIntrinsic(Intrinsic::trap, {});
115 
116   uint64_t ImmArg = GuardKind.has_value()
117                         ? GuardKind.value()
118                         : IRB.GetInsertBlock()->getParent()->size();
119   // Ensure we constrain ImmArg to fitting within a 8-but unsigned integer to
120   // prevent overflow.
121   if (ImmArg > 255)
122     ImmArg = 255;
123 
124   return IRB.CreateIntrinsic(Intrinsic::ubsantrap,
125                              ConstantInt::get(IRB.getInt8Ty(), ImmArg));
126 }
