128 static CallInst *InsertCall(BuilderTy &IRB, bool MayReturn, StringRef Name) {
129   Function *Fn = IRB.GetInsertBlock()->getParent();
130   LLVMContext &Ctx = Fn->getContext();
131   llvm::AttrBuilder B(Ctx);
132   B.addAttribute(llvm::Attribute::NoUnwind);
133   if (!MayReturn)
134     B.addAttribute(llvm::Attribute::NoReturn);
135   FunctionCallee Callee = Fn->getParent()->getOrInsertFunction(
136       Name,
137       llvm::AttributeList::get(Ctx, llvm::AttributeList::FunctionIndex, B),
138       Type::getVoidTy(Ctx));
139   return IRB.CreateCall(Callee);
140 }
